const FALLBACK_ICON: LanguageIconInfo = {
	svg: `<svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>`,
	label: 'Code',
	color: '#6B7280'
};

export function getLanguageIcon(lang: string): LanguageIconInfo {
	if (!lang) return FALLBACK_ICON;

	const normalized = lang.toLowerCase().trim();
	const canonical = LANG_ALIASES[normalized] ?? normalized;

	if (LANGUAGE_ICONS[canonical]) {
		return LANGUAGE_ICONS[canonical];
	}

	return {
		...FALLBACK_ICON,
		label: lang.charAt(0).toUpperCase() + lang.slice(1)
	};
}
